import { Component } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { Evento } from '@app/models/Evento';
import { EventoService } from '@app/services/evento.service';
import { BsLocaleService } from 'ngx-bootstrap/datepicker';
import { NgxSpinnerService } from 'ngx-spinner';
import { ToastrService } from 'ngx-toastr';

@Component({
  selector: 'app-evento-detalhe',
  templateUrl: './evento-detalhe.component.html',
  styleUrls: ['./evento-detalhe.component.scss']
})
export class EventoDetalheComponent {

  evento = { } as Evento; //obj vazio ja inicializada
  modoSalvar = 'post'; //instancia em modo post (novo)

  form!: FormGroup;
  get f(): any{
    return this.form.controls;
  }

  get bsConfig(): any{
    return {
      adaptivePosition: true,
      dateInputFormat: 'DD/MM/YYYY hh:mm a',
      containerClass: 'theme-default',
      showWeekNumbers: false
    }
  }

  constructor(private fb: FormBuilder,
              private localeService: BsLocaleService,
              private router: ActivatedRoute,
              private eventoService: EventoService,
              private spinner: NgxSpinnerService,
              private toaster: ToastrService)
  {
    this.localeService.use('pt-br');
  }

  //pega o id do evento e copia os items só para alteração
  public carregarEvento(): void{
    const eventoIdParam = this.router.snapshot.paramMap.get('id');

    if(eventoIdParam != null){
      //carregamento
      this.spinner.show();
      this.modoSalvar = 'put'; //quando ele nao é nulo ele vira atualizar

      this.eventoService.getEventosById(+eventoIdParam).subscribe({
        next: (evento: Evento) => {
          this.evento = {... evento};
          this.form.patchValue(this.evento);
        }, //copia todos os items de evento
        error: (error: any) => {
          this.spinner.hide(),
          this.toaster.error('Erro ao tentar carregar Evento.'),
          console.log(error)
        },
        complete: () => this.spinner.hide()
      });
      // + na frente converte pra int
    }
  }

  ngOnInit(): void{
    this.validation();
    this.carregarEvento();
  }

  public validation(): void{
    this.form = this.fb.group({
      tema: ['', [Validators.required, Validators.minLength(4), Validators.maxLength(50)]],
      local: ['', Validators.required ], 
      dataEvento: ['', Validators.required ],
      qtdPessoas: ['', [Validators.required, Validators.max(120000)]],
      telefone: ['', Validators.required ],
      email: ['',[Validators.required, Validators.email]],
      imagemURL: ['', Validators.required],
      //['aqui vai o placeholder', Validators.limitadores]
    });
  }

  public resetForm():void{
    this.form.reset();
  }

  public cssValidator(campoForm: FormControl): any {
    return {'is-invalid': campoForm.errors && campoForm.touched}
  }

  public salvarAlteracao(): void {
    this.spinner.show();
    if(this.form.valid){

      this.evento = (this.modoSalvar === 'post') 
                  ? { ... this.form.value}
                  : {id: this.evento.id, ... this.form.value};

      this.eventoService[this.modoSalvar](this.evento).subscribe(
        () => this.toaster.success('Evento salvo com sucesso!', 'Sucesso'),
        (error: any) => {
          console.error(error);
          this.spinner.hide();
          this.toaster.error('Erro ao salvar evento', 'Erro');
        },
        () => this.spinner.hide()
      )add();
    }
  }
}
<div class="card rounded shadow-sm">
    <form [formGroup]="form">
        <div class="p-3">
            <div class="form-row">
                <div class="form-group col-md-12">
                    <label>Tema</label>
                    <input type="text" class="form-control"
                     [ngClass]="cssValidator(f.tema)"
                     formControlName="tema" placeholder="Insira o Tema">
                    <!-- atribui o css caso tenha erros e seja tocado
                    atribui as mensagens certas-->
                    <div *ngIf="f.tema.errors?.required" 
                    class="invalid-feedback">
                        Tema é Obrigatorio
                    </div>
                    <div *ngIf="f.tema.errors?.minlength"
                    class="invalid-feedback">
                        Tema deve ter no mínimo 4 caracteres.
                    </div>
                    <div *ngIf="f.tema.errors?.maxlength"
                    class="invalid-feedback">
                        Tema deve ter no máximo 50 caracteres.
                    </div>

                </div>
            </div>

            <div class="form-row">
                <div class="form-group col-md-8">
                    <label>Local</label>
                    <input type="text" class="form-control" 
                    [ngClass]="cssValidator(f.local)"
                    formControlName="local" placeholder="">

                    <div *ngIf="f.local.errors?.required" 
                    class="invalid-feedback">
                        Local é Obrigatorio.
                    </div>

                </div>
                <div class="form-group col-md-4">
                    <label>Data e Hora</label>
                    <input type="datetime" class="form-control" 
                    [ngClass]="cssValidator(f.dataEvento)"
                    value="{{evento.dataEvento | DateFormat}}"
                    bsDatepicker [bsConfig]="bsConfig"
                    formControlName="dataEvento" placeholder="">

                    <div *ngIf="f.dataEvento.errors?.required" 
                    class="invalid-feedback">
                        Data e Hora é Obrigatorio.
                    </div>

                </div>
            </div>

            <div class="form-row">
                <div class="form-group col-md-2">
                    <label>Qtd Pessoas</label>
                    <input type="text" class="form-control" 
                    [ngClass]="cssValidator(f.qtdPessoas)"
                    formControlName="qtdPessoas" placeholder="">

                    <div *ngIf="f.qtdPessoas.errors?.required" 
                    class="invalid-feedback">
                        Qtd Pessoas é Obrigatorio.
                    </div>
                    <div *ngIf="f.qtdPessoas.errors?.max" 
                    class="invalid-feedback">
                        Qtd Pessoas ultrapassou o limite.
                    </div>

                </div>
                <div class="form-group col-md-2">
                    <label>Telefone</label>
                    <input type="text" class="form-control" 
                    [ngClass]="cssValidator(f.telefone)"
                    formControlName="telefone" placeholder="(000) 90000-0000">

                    <div *ngIf="f.telefone.errors?.required" 
                    class="invalid-feedback">
                        Telefone é Obrigatorio.
                    </div>

                </div>
                <div class="form-group col-md-4">
                    <label>e-mail</label>
                    <input type="text" class="form-control" 
                    [ngClass]="cssValidator(f.email)"
                    formControlName="email" placeholder="e-mail">

                    <div *ngIf="f.email.errors?.required" 
                    class="invalid-feedback">
                        e-mail é Obrigatorio.
                    </div>
                    <div *ngIf="f.email.errors?.email" 
                    class="invalid-feedback">
                        formato de e-mail invalido.
                    </div>

                </div>
                <div class="form-group col-md-4">
                    <label>Imagem</label>
                    <input type="text" class="form-control" 
                    [ngClass]="cssValidator(f.imagemURL)"
                    formControlName="imagemURL" placeholder="imagem">

                    <div *ngIf="f.imagemURL.errors?.required" 
                    class="invalid-feedback">
                        Imagem é Obrigatorio.
                    </div>

                </div>

            </div>

        </div>

        <div class="card-footer">
            <!-- cor diferente fofinha -->
            <div class="d-flex">
                <button class="btn btn-outline-secondary mr-auto border"
                (click)="resetForm()"> <!--limpa forms-->
                    Cancelar Alteração
                </button>
                <button class="btn btn-success" [disabled]="!form.valid" (click)="salvarAlteracao()">
                    <span class="spinner-border spinner-border-sm mr-1"></span>
                    <!--spinner = da uma animação de carregando-->
                    Salvar Evento
